mapper.insert:
insert into course

    course_code
    course_name
    credit
    hours
    type
    status
    capacity

    values

    #{courseCode}
    #{courseName}
    #{credit}
    #{hours}
    #{type}
    #{status}
    #{capacity}

mapper.update:
update course

    course_name = #{courseName}
    credit = #{credit}
    hours = #{hours}
    type = #{type}
    status = #{status}
    capacity = #{capacity}

where id = #{id}

mapper.select:
select id, course_code, course_name, credit, hours, type, status, create_time,capacity from course
course_code like concat('%', #{courseCode}, '%') and course_name like concat('%', #{courseName}, '%') and type = #{type} and status = #{status}
order by create_time desc
